sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	function TestCase_IsAgenticConversationIdleOrInactive(vConversation,vExpected)
	{
		function TestCase_IsAgenticConversationIdleOrInactive_CheckResult(vInput,vExpected,vResult)
		{
			return (vExpected == vResult);
		}
		
		test.TestCase(
			'Function IsAgenticConversationIdleOrInactive()',
			IsAgenticConversationIdleOrInactive,
			{
				'vConversation': vConversation
			},
			vExpected,
			TestCase_IsAgenticConversationIdleOrInactive_CheckResult);
	}
		
	TestCase_IsAgenticConversationIdleOrInactive(null,true);

	var strAgentSysId = '3e0035478367121085a2c407a22bc0d0';
	var grAgent = GetRecord('sn_aia_agent',strAgentSysId);

	if (IsValidRecord(grAgent) == true)
	{
		var grProblem = new GlideRecord('problem');
		grProblem.initialize();
		grProblem.short_description = 'A lot of user complaints';
		var strProblemSysId = GlideRecordInsert(grProblem);

		var strConversationSysId = StartAgenticConversation(
			'Problem investigator',
			'Help me to analyze this problem',
			grProblem,
			null,
			true);

		TestCase_IsAgenticConversationIdleOrInactive(strConversationSysId,false);

		// This gives the agent some time to finish its work and wait for further user input
		Sleep(30);

		TestCase_IsAgenticConversationIdleOrInactive(strConversationSysId,true);

	}

	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
